import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
});

// Upload brand voice documents
const brandStore = await vex.embeddingStores.create({
  name: 'content-brand-voice',
  documents: [
    {
      content: 'Our brand voice is conversational, optimistic, and approachable. Use short sentences. Avoid jargon. Always end with a clear CTA.',
      metadata: { type: 'style_guide', section: 'tone' }
    },
    {
      content: 'Target audience: Tech-savvy millennials. Use emojis sparingly. Focus on benefits over features.',
      metadata: { type: 'audience', priority: 'high' }
    }
  ]
});

console.log('Brand voice store ID:', brandStore.id);

const factCheckVerifier = await vex.verifiers.create({
  name: 'content-fact-check',
  checks: [
    {
      type: 'factual_accuracy',
      name: 'web_source_validation',
      threshold: 0.9,
      providers: ['perplexity', 'tavily'],
      prompt: `Verify these claims from the generated content against current web sources:
{{input.claims}}

Flag any statements that cannot be confirmed by 2+ reputable sources.`
    },
    {
      type: 'plagiarism_check',
      name: 'originality_scan',
      threshold: 0.95,
      provider: 'copyleaks'
    }
  ]
});

const seoVerifier = await vex.verifiers.create({
  name: 'content-seo-compliance',
  checks: [
    {
      type: 'keyword_density',
      name: 'primary_keyword_usage',
      parameters: {
        keywords: ['{{input.primaryKeyword}}'],
        minDensity: 0.015,
        maxDensity: 0.03
      }
    },
    {
      type: 'readability',
      name: 'flesch_reading_ease',
      parameters: {
        minScore: 60,
        maxSentencesPerParagraph: 4
      }
    },
    {
      type: 'structure',
      name: 'heading_hierarchy',
      parameters: {
        requireH2: true,
        maxH2Count: 8
      }
    }
  ]
});

// n8n Webhook Node - POST configuration
const webhookResponse = await vex.verify({
  input: {
    content: $input.first().json.aiAgentOutput,
    topic: $input.first().json.topic,
    primaryKeyword: $input.first().json.primaryKeyword,
    brandGuidelines: $input.first().json.brandVoice
  },
  verifierIds: [
    'content-brand-voice',
    'content-fact-check',
    'content-seo-compliance'
  ],
  embeddingStoreId: 'content-brand-voice',
  context: {
    workflowExecutionId: $execution.id,
    agentNode: 'Content Generator'
  }
});

// Return verified content or block workflow
if (webhookResponse.passed) {
  return {
    verifiedContent: webhookResponse.output.content,
    scores: webhookResponse.scores,
    proceed: true
  };
} else {
  throw new Error(`Content blocked: ${webhookResponse.issues.map(i => i.reason).join(', ')}`);
}

