// n8n HTTP Request Node configuration
const response = await fetch('https://api.vex.dev/v1/verify', {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${$secrets.VEX_API_KEY}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    input: {
      content: $json.content,
      claims: extractClaims($json.content),
      targetKeyword: $json.keyword
    },
    verifierIds: ['content-brand-voice', 'content-fact-check'],
    embeddingStoreId: 'content-brand-voice',
    workflowContext: {
      n8nNode: $node.name,
      executionId: $execution.id
    }
  })
});

const result = await response.json();

if (!result.passed) {
  // Block workflow and notify
  return [{ json: { blocked: true, issues: result.issues } }];
}

// Pass verified content
return [{ json: { ...$json, verified: true, vexScores: result.scores } }];

const monitor = await vex.monitors.create({
  name: 'content-brand-drift',
  query: {
    embeddingStoreId: 'content-brand-voice',
    metric: 'cosine_similarity',
    threshold: 0.75,
    timeWindow: '30d',
    filters: {
      workflow: 'content-generation',
      contentType: ['blog_post', 'social_copy']
    }
  },
  alertConfig: {
    slack: process.env.SLACK_WEBHOOK_URL,
    threshold: 5,
    message: `🚨 Brand voice drift detected! {{count}} pieces fell below 75% similarity\nWorst offender: {{worstItem.contentPreview}}\nScore: {{worstItem.score}}`
  }
});

const finalGate = await vex.verifiers.create({
  name: 'pre-publish-final',
  checks: [
    {
      type: 'aggregate_score',
      name: 'overall_quality',
      parameters: {
        minCompositeScore: 0.88,
        requiredChecks: ['brand_voice', 'facts', 'seo'],
        weights: { brand_voice: 0.4, facts: 0.35, seo: 0.25 }
      }
    },
    {
      type: 'human_review_trigger',
      name: 'editorial_escalation',
      parameters: {
        triggerConditions: [
          'brand_voice < 0.75',
          'factual_accuracy < 0.85',
          'plagiarism > 0.10'
        ],
        notify: ['editor@company.com']
      }
    }
  ]
});
